eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   addContactMessage: () => (/* binding */ addContactMessage),\n/* harmony export */   addDonation: () => (/* binding */ addDonation),\n/* harmony export */   addEventRequest: () => (/* binding */ addEventRequest),\n/* harmony export */   addPartnershipSubmission: () => (/* binding */ addPartnershipSubmission),\n/* harmony export */   addVolunteerSubmission: () => (/* binding */ addVolunteerSubmission),\n/* harmony export */   getAdminStats: () => (/* binding */ getAdminStats),\n/* harmony export */   getContactMessages: () => (/* binding */ getContactMessages),\n/* harmony export */   getDonations: () => (/* binding */ getDonations),\n/* harmony export */   getEventRequests: () => (/* binding */ getEventRequests),\n/* harmony export */   getPartnershipSubmissions: () => (/* binding */ getPartnershipSubmissions),\n/* harmony export */   getVolunteerSubmissions: () => (/* binding */ getVolunteerSubmissions),\n/* harmony export */   markContactRead: () => (/* binding */ markContactRead),\n/* harmony export */   saveContactMessages: () => (/* binding */ saveContactMessages),\n/* harmony export */   updateAdminStats: () => (/* binding */ updateAdminStats)\n/* harmony export */ });\n/* __next_internal_client_entry_do_not_use__ getContactMessages,addContactMessage,markContactRead,saveContactMessages,getPartnershipSubmissions,addPartnershipSubmission,getAdminStats,updateAdminStats,getVolunteerSubmissions,addVolunteerSubmission,getEventRequests,addEventRequest,getDonations,addDonation auto */ // ─── Storage keys ─────────────────────────────────────────────────────────────\nconst KEYS = {\n    contacts: 'stepup_contact_messages',\n    partnerships: 'stepup_partnership_submissions',\n    volunteers: 'stepup_volunteer_submissions',\n    eventRequests: 'stepup_event_requests',\n    stats: 'stepup_admin_stats',\n    donations: 'stepup_donations'\n};\n// ─── Seed data ────────────────────────────────────────────────────────────────\nconst DEFAULT_CONTACTS = [\n    {\n        id: 1,\n        from: 'GreenEarth NGO',\n        email: 'contact@greenearth.org',\n        subject: 'Partnership Application Follow-up',\n        body: 'Hello, we submitted our partnership application 3 days ago and wanted to check on its status. We are very eager to collaborate on SDG 13 initiatives.',\n        time: '10:32 AM',\n        date: 'Today',\n        unread: true,\n        tag: 'Partner',\n        avatar: 'G'\n    },\n    {\n        id: 2,\n        from: 'Bright Futures Academy',\n        email: 'admin@brightfutures.edu',\n        subject: 'SDG 4 Program Enrollment Query',\n        body: 'We would like to enroll our school in the SDG 4 Quality Education program. Could you please send us the requirements and onboarding steps?',\n        time: '9:15 AM',\n        date: 'Today',\n        unread: true,\n        tag: 'School',\n        avatar: 'B'\n    },\n    {\n        id: 3,\n        from: 'EcoSolutions Ltd',\n        email: 'info@ecosolutions.com',\n        subject: 'Q3 Impact Report Submission',\n        body: 'Please find attached our Q3 impact report for the Clean Water Access project. All milestones have been achieved ahead of schedule.',\n        time: 'Yesterday',\n        date: 'Yesterday',\n        unread: false,\n        tag: 'Partner',\n        avatar: 'E'\n    },\n    {\n        id: 4,\n        from: 'Hope Foundation',\n        email: 'team@hopefoundation.org',\n        subject: 'Funding Collaboration Proposal',\n        body: 'We are reaching out to propose a joint funding initiative for SDG 1 and SDG 2.',\n        time: 'Mon',\n        date: 'Mon',\n        unread: false,\n        tag: 'Partner',\n        avatar: 'H'\n    }\n];\nconst DEFAULT_PARTNERSHIPS = [\n    {\n        id: 1,\n        fullName: 'Maria Rodriguez',\n        organization: 'Sunrise Cooperative',\n        email: 'maria@sunrise.org',\n        type: 'NGO',\n        message: 'We want to collaborate on SDG 2 — Zero Hunger initiatives in rural communities.',\n        submittedAt: '2024-09-21'\n    },\n    {\n        id: 2,\n        fullName: 'Daniel Park',\n        organization: 'OceanGuard Initiative',\n        email: 'daniel@oceanguard.org',\n        type: 'NGO',\n        message: 'Interested in partnering on Life Below Water programs.',\n        submittedAt: '2024-09-18'\n    },\n    {\n        id: 3,\n        fullName: 'Aisha Bello',\n        organization: 'Lagos Youth Lab',\n        email: 'aisha@lagosyouth.org',\n        type: 'NGO',\n        message: 'We run quality education programs for youth in Lagos and would love to align with SDG 4.',\n        submittedAt: '2024-09-12'\n    }\n];\nconst DEFAULT_STATS = {\n    totalPartners: 1248,\n    totalProjects: 386,\n    totalEvents: 156,\n    totalStudents: 12450,\n    schoolsSupported: 142,\n    pendingRequests: 24,\n    activeCampaigns: 38,\n    studentContributions: 4820\n};\n// ─── Helpers ──────────────────────────────────────────────────────────────────\nfunction load(key, fallback) {\n    if (true) return fallback;\n    try {\n        const raw = localStorage.getItem(key);\n        if (!raw) {\n            localStorage.setItem(key, JSON.stringify(fallback));\n            return fallback;\n        }\n        return JSON.parse(raw);\n    } catch  {\n        return fallback;\n    }\n}\nfunction save(key, value) {\n    if (true) return;\n    localStorage.setItem(key, JSON.stringify(value));\n}\n// ─── Contact Messages ─────────────────────────────────────────────────────────\nfunction getContactMessages() {\n    return load(KEYS.contacts, DEFAULT_CONTACTS);\n}\nfunction addContactMessage(msg) {\n    const messages = getContactMessages();\n    const newMsg = {\n        ...msg,\n        id: Date.now(),\n        unread: true,\n        avatar: msg.from.charAt(0).toUpperCase()\n    };\n    save(KEYS.contacts, [\n        newMsg,\n        ...messages\n    ]);\n    const stats = getAdminStats();\n    save(KEYS.stats, {\n        ...stats,\n        pendingRequests: stats.pendingRequests + 1\n    });\n}\nfunction markContactRead(id) {\n    const messages = getContactMessages();\n    save(KEYS.contacts, messages.map((m)=>m.id === id ? {\n            ...m,\n            unread: false\n        } : m));\n}\nfunction saveContactMessages(messages) {\n    save(KEYS.contacts, messages);\n}\n// ─── Partnership Submissions ──────────────────────────────────────────────────\nfunction getPartnershipSubmissions() {\n    return load(KEYS.partnerships, DEFAULT_PARTNERSHIPS);\n}\nfunction addPartnershipSubmission(sub) {\n    const submissions = getPartnershipSubmissions();\n    const newSub = {\n        ...sub,\n        id: Date.now(),\n        submittedAt: new Date().toISOString().split('T')[0]\n    };\n    save(KEYS.partnerships, [\n        newSub,\n        ...submissions\n    ]);\n    const stats = getAdminStats();\n    save(KEYS.stats, {\n        ...stats,\n        pendingRequests: stats.pendingRequests + 1\n    });\n}\n// ─── Admin Stats ──────────────────────────────────────────────────────────────\nfunction getAdminStats() {\n    return load(KEYS.stats, DEFAULT_STATS);\n}\nfunction updateAdminStats(patch) {\n    const stats = getAdminStats();\n    save(KEYS.stats, {\n        ...stats,\n        ...patch\n    });\n}\n// ─── Volunteer Submissions ─────────────────────────────────────────────────────\nfunction getVolunteerSubmissions() {\n    return load(KEYS.volunteers, []);\n}\nfunction addVolunteerSubmission(v) {\n    const list = getVolunteerSubmissions();\n    save(KEYS.volunteers, [\n        {\n            ...v,\n            id: Date.now(),\n            submittedAt: new Date().toISOString().split('T')[0]\n        },\n        ...list\n    ]);\n    const stats = getAdminStats();\n    save(KEYS.stats, {\n        ...stats,\n        pendingRequests: stats.pendingRequests + 1\n    });\n}\n// ─── Event Requests ─────────────────────────────────────────────────────────────\nfunction getEventRequests() {\n    return load(KEYS.eventRequests, []);\n}\nfunction addEventRequest(r) {\n    const list = getEventRequests();\n    save(KEYS.eventRequests, [\n        {\n            ...r,\n            id: Date.now(),\n            submittedAt: new Date().toISOString().split('T')[0]\n        },\n        ...list\n    ]);\n    const stats = getAdminStats();\n    save(KEYS.stats, {\n        ...stats,\n        pendingRequests: stats.pendingRequests + 1\n    });\n}\n// ─── Donations ────────────────────────────────────────────────────────────────\nfunction getDonations() {\n    return load(KEYS.donations, []);\n}\nfunction addDonation(d) {\n    const list = getDonations();\n    save(KEYS.donations, [\n        {\n            ...d,\n            id: Date.now(),\n            donatedAt: new Date().toISOString()\n        },\n        ...list\n    ]);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./app/lib/adminStore.ts\n");

